import { Calendar, User, Bot } from 'lucide-react'
import { Card, CardHeader, CardContent } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import useChatStore from '@/stores/useChatStore'

export default function AdminConversations() {
  const { logs, clearLogs } = useChatStore()

  return (
    <div className="space-y-6 max-w-5xl animate-fade-in">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <h1 className="text-3xl font-bold tracking-tight">Histórico de Conversas da IA</h1>
        {logs.length > 0 && (
          <Button
            variant="outline"
            onClick={clearLogs}
            className="text-destructive hover:bg-destructive/10"
          >
            Limpar Histórico
          </Button>
        )}
      </div>

      <div className="grid gap-4">
        {logs.length === 0 ? (
          <Card>
            <CardContent className="p-8 text-center text-muted-foreground">
              Nenhuma conversa registrada ainda.
            </CardContent>
          </Card>
        ) : (
          logs.map((log) => (
            <Card key={log.id} className="overflow-hidden shadow-sm">
              <CardHeader className="bg-muted/50 p-4 border-b">
                <div className="flex items-center gap-2 text-sm text-muted-foreground font-medium">
                  <Calendar className="w-4 h-4" />
                  {new Date(log.date).toLocaleString('pt-BR')}
                </div>
              </CardHeader>
              <CardContent className="p-0">
                <div className="flex flex-col">
                  <div className="p-4 bg-background border-b flex gap-3">
                    <div className="w-8 h-8 rounded-full bg-primary/10 text-primary flex items-center justify-center shrink-0">
                      <User className="w-4 h-4" />
                    </div>
                    <div>
                      <p className="text-xs font-semibold text-muted-foreground mb-1 uppercase tracking-wider">
                        Usuário
                      </p>
                      <p className="text-sm font-medium">{log.query}</p>
                    </div>
                  </div>
                  <div className="p-4 bg-muted/30 flex gap-3">
                    <div className="w-8 h-8 rounded-full bg-primary text-primary-foreground flex items-center justify-center shrink-0">
                      <Bot className="w-4 h-4" />
                    </div>
                    <div className="flex-1">
                      <p className="text-xs font-semibold text-muted-foreground mb-1 uppercase tracking-wider">
                        Assistente IA
                      </p>
                      <p className="text-sm whitespace-pre-wrap leading-relaxed">{log.response}</p>
                    </div>
                  </div>
                </div>
              </CardContent>
            </Card>
          ))
        )}
      </div>
    </div>
  )
}
